import React ,{useState}from 'react'

function UploadProduct() {
    const [title, settitle] = useState("")
    const [desc, setdesc] = useState("")
    const titlechange =(event)=>{
        settitle(event.currentTarget.value)
    }
    const descchange =(event)=>{
        setdesc(event.currentTarget.value)
    }
    return (
        <div className="container" style={{margin:'2rem auto'}}>
            <div  style={{margin:'2rem auto', textAlign:'center'}}>
                <h2>Upload your Product here</h2>
            </div>

            <form onSubmit>
                {/* Dropzone */}


                {/* title */}
                <label className="my-3">Title</label>
                <input  className="my-1" onChange={titlechange} value={title}/>
                <br />
                <br />
                {/* description */}
                <label  className="my-3">Description</label>
                <textarea  className="my-1" onChange={descchange} value={desc}/>
                <br />
                <br />
                {/* price */}
                <label  className="my-3">Price</label>
                <input  className="my-1" onChange value type="number"/>
                <br />
                <br />
                {/* brand: */}
                <select  className="my-3">
                    <option  className="my-1" key="" value=""></option>
                </select >
                <br />
                <br />
                {/* category */}
                <select  className="my-3">
                    <option  className="my-1" key="" value=""></option>
                </select>
                <br />
                <br />
                {/* countInStock */}
                <label className="my-3">Price</label>
                <input  className="my-1" onChange value type="number"/>
                <br />
                <br />
                {/* submit button */}
                <button className="btn btn-primary my-3" onClick>Submit</button>
            </form>
        </div>
    )
}

export default UploadProduct
